VALUES
  ('social-worker-moex-06450', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '有獻不死之藥於荊王者，謁者操之以入，中射之士問曰：「可食乎？」曰：「可。」 因奪而食之，王大怒，使人殺中射之士。中射之士使人說王曰：「臣問謁者，曰『可 食』，臣故食之，是臣無罪，而罪在謁者也。且客獻不死之藥，臣食之而王殺臣， 是死藥也，是客欺王也。夫殺無罪之臣，而明人之欺王也，不如釋臣。」王乃不殺。 （《韓非子．說林上》） 依據上文，中射之士吃了荊王的不死之藥，卻可免於死罪的原因是：', '["荊王謙沖為懷，勤政愛民", "荊王欲擒故縱，虛心假意", "中射之士親身試藥，感動荊王", "中射之士善於詭辯，荊王因而釋懷"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06451', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「昔者鄭武公欲伐胡，故先以其女妻胡君以娛其意。因問於群臣：『吾欲用兵，誰 可伐者？』大夫關其思對曰：『胡可伐。』武公怒而戮之，曰：『胡，兄弟之國 也，子言伐之何也？』胡君聞之，以鄭為親己，遂不備鄭，鄭人襲胡，取之。」 （《韓非子．說難》） 下列何者最接近此文所表達的意涵？', '["偷雞不著，卻蝕把米", "將取先予，欲擒故縱", "殺雞儆猴，以一戒百", "不念舊惡，親情至上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "bdb2fa9e8569", "answer_pdf_sha1": "4961f10a12fc", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
