  ('social-worker-moex-06454', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一個有關於CEDAW的陳述是錯誤的？', '["聯合國帶領一連串引起世界關注有關女性遭受暴力與性侵害的議題", "消除對婦女一切形式歧視公約", "馬德里宣言與行動綱領", "消除對婦女暴力宣言"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "a3d845e75c7c", "answer_pdf_sha1": "ca9f253103ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
